import asyncio
import aiohttp
import threading
import time
from collections import OrderedDict

class HTTPError(Exception):
    def __init__(self, response):
        self.response = response
        super().__init__(f"HTTP Error {response.status}: {response.text}")

class ApiClient:
    def __init__(self, base_url, timeout=10):
        self.base_url = base_url
        self.timeout = timeout
        self.session = aiohttp.ClientSession(timeout=aiohttp.ClientTimeout(total=timeout))

    async def get(self, endpoint):
        url = f"{self.base_url}{endpoint}"
        async with self.session.get(url) as response:
            if response.status != 200:
                raise HTTPError(response)
            return await response.json()

    async def post(self, endpoint, json=None):
        url = f"{self.base_url}{endpoint}"
        headers = {"Content-Type": "application/json"}
        async with self.session.post(url, json=json, headers=headers) as response:
            if response.status != 201:
                raise HTTPError(response)
            return await response.json()

    async def close(self):
        await self.session.close()

class LRUCache:
    def __init__(self, ttl, max_size, eviction_strategy="eager"):
        self.ttl = ttl
        self.max_size = max_size
        self.eviction_strategy = eviction_strategy
        self.cache = OrderedDict()
        self.lock = threading.RLock()

    def set(self, key, value):
        with self.lock:
            if key in self.cache:
                self.cache.move_to_end(key)
            self.cache[key] = {"value": value, "timestamp": time.time()}
            if len(self.cache) > self.max_size:
                self._evict()

    def get(self, key):
        with self.lock:
            if key in self.cache:
                if self._is_expired(key):
                    del self.cache[key]
                    return None
                self.cache.move_to_end(key)
                return self.cache[key]["value"]
            return None

    def size(self):
        with self.lock:
            return len(self.cache)

    def _is_expired(self, key):
        if self.eviction_strategy == "eager":
            return time.time() - self.cache[key]["timestamp"] > self.ttl
        return False

    def _evict(self):
        if self.eviction_strategy == "eager":
            while len(self.cache) > self.max_size:
                self.cache.popitem(last=False)
        elif self.eviction_strategy == "lazy":
            for key in list(self.cache.keys()):
                if self._is_expired(key):
                    del self.cache[key]
